<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">    &quot;model&quot;: &quot;&#39;&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">$MODEL</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">&quot;&#39;&quot;,</span></span>
